export interface OfficialRelease {
  date: string             // 'YYYY-MM-DD'
  series: string            // "Dick's Picks" | "Dave's Picks" | "Road Trips" | "Download Series"
                             // | "From the Vault" | "Studio/Compilation" | "Play Dead"
  title: string              // "Dick's Picks Vol. 1", "Cornell 5/8/77", etc.
  volume?: string
  contributingOnly?: boolean   // true when the release only contributes a partial night (a few songs
                                 // pulled into a compilation) rather than the whole show
}

// One row per show date — if a show has multiple releases (a Dick's Picks volume plus a later
// box-set reissue, say), only the most identifiable one is kept: named archival series (Dick's
// Picks / Dave's Picks / Road Trips / Download Series / From the Vault) win over generic
// compilations, and the release covering the fewest other dates wins among ties, so a dedicated
// single-show title like "Cornell 5/8/77" beats a many-date anthology like "Beyond Description".
// Source: deaddisc.com's Grateful Dead Family Discography, "releases by recording date" tables.
// Play Dead app catalog (422 shows, weekly additions) needs its own scrape/source — zero Play
// Dead rows to start.
