export function getOfficialReleasesForDate(date: string): OfficialRelease[] {
  return RELEASES.filter(r => r.date === date)
}

export function getOfficialReleasesForDates(dates: string[]): OfficialRelease[] {
  const dateSet = new Set(dates)
  return RELEASES.filter(r => dateSet.has(r.date))
}

export function hasOfficialRelease(date: string): boolean {
  return RELEASES.some(r => r.date === date)
}
